const podcastLink =
  $('Upload to Google Drive').first().json.webViewLink ||
  $('Upload to Google Drive').first().json.webContentLink ||
  "";

return [
  {
    json: {
      html: `
        <h1>Veille IA du jour</h1>
        <hr>
        <div style="white-space: pre-wrap;">${briefing}</div>
        <hr>
        <p><strong>Podcast du jour :</strong></p>
        <p><a href="${podcastLink}">Écouter le podcast</a></p>
      `
    }
  }
];

return [
  {
    json: {
      status: "done",
      completed_at: new Date().toISOString()
    }
  }
];

const input = $input.all().map(item => item.json);

const now = new Date();
const HOURS_BACK = 168; // 7 jours

function clean(text = "") {
  return String(text)
    .replace(/&#8217;/g, "’")
    .replace(/&#8216;/g, "‘")
    .replace(/&#8220;/g, "“")
    .replace(/&#8221;/g, "”")
    .replace(/&#8211;/g, "–")
    .replace(/&#8212;/g, "—")
    .replace(/&#8230;/g, "…")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/<[^>]*>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getDate(article) {
  return article.isoDate || article.pubDate || article.date || "";
}


function getSource(article) {
  const link = article.link || article.url || "";
  const rawFeedTitle = clean(article.feedTitle || "");

  if (rawFeedTitle) return rawFeedTitle;

  if (link.includes("openai.com")) return "OpenAI";
  if (link.includes("anthropic.com")) return "Anthropic";
  if (link.includes("deepmind.google")) return "Google DeepMind";
  if (link.includes("blog.google")) return "Google Blog";
  if (link.includes("research.google")) return "Google Research";
  if (link.includes("huggingface.co")) return "Hugging Face";
  if (link.includes("technologyreview.com")) return "MIT Technology Review";
  if (link.includes("venturebeat.com")) return "VentureBeat";
  if (link.includes("techcrunch.com")) return "TechCrunch";
  if (link.includes("wired.com")) return "Wired";
  if (link.includes("hai.stanford.edu")) return "Stanford HAI";
  if (link.includes("deeplearning.ai")) return "DeepLearning.AI";
  if (link.includes("developpez.com")) return "Developpez.com IA";

  return "Unknown";
}

function getSummary(article) {
  if (article["content:encodedSnippet"]) {
    return clean(article["content:encodedSnippet"]).slice(0, 400);
  }

  if (article.contentSnippet) {
    return clean(article.contentSnippet).slice(0, 400);
  }

  if (article.description) {
    return clean(article.description).slice(0, 400);
  }

  if (article["content:encoded"]) {
    return clean(article["content:encoded"]).slice(0, 400);
  }

  if (article.content) {
    return clean(article.content).slice(0, 400);
  }

  return "";
}

function getTheme(article) {
  const text = clean(`
    ${article.title || ""}
    ${article["content:encodedSnippet"] || ""}
    ${article.contentSnippet || ""}
    ${article.description || ""}
    ${article["content:encoded"] || ""}
    ${article.content || ""}
    ${article.summary || ""}
    ${article.feedTitle || ""}
  `).toLowerCase();

  if (
    text.includes("agent") ||
    text.includes("agents") ||
    text.includes("automation") ||
    text.includes("copilot")
  ) {
    return "Automatisation & Agents";
  }

  if (
    text.includes("openai") ||
    text.includes("anthropic") ||
    text.includes("google") ||
    text.includes("gemini") ||
    text.includes("deepmind") ||
    text.includes("funding") ||
    text.includes("partnership") ||
    text.includes("enterprise")
  ) {
    return "Acteurs & Stratégies";
  }

  if (
    text.includes("tool") ||
    text.includes("tools") ||
    text.includes("studio") ||
    text.includes("model") ||
    text.includes("sdk") ||
    text.includes("api") ||
    text.includes("tts")
  ) {
    return "Outils & Produits IA";
  }

  if (
    text.includes("customer") ||
    text.includes("workflow") ||
    text.includes("deployment") ||
    text.includes("operations") ||
    text.includes("productivity") ||
    text.includes("use case")
  ) {
    return "Cas d’usage concrets";
  }

  return "Tendances & Signaux faibles";
}

function isRecent(date) {
  if (!date) return false;
  const d = new Date(date);
  if (isNaN(d.getTime())) return false;
  const diff = (now - d) / (1000 * 60 * 60);
  return diff <= HOURS_BACK;
}

function isNoise(article) {
  const title = clean(article.title || "").toLowerCase();
  return (
    title.includes("the download") ||
    title.includes("pie day") ||
    title.includes("newsletter") ||
    title.includes("podcast")
  );
}

const sourceCountsBefore = {};
for (const a of input) {
  const source = getSource(a);
  sourceCountsBefore[source] = (sourceCountsBefore[source] || 0) + 1;
}

const seen = new Set();

const deduped = input.filter(a => {
  const key = clean((a.link || a.url || a.title || "").toLowerCase())
    .replace(/[^a-z0-9]/g, "")
    .slice(0, 120);

  if (!key || seen.has(key)) return false;
  seen.add(key);
  return true;
});

const filtered = deduped
  .filter(a => isRecent(getDate(a)))
  .filter(a => !isNoise(a))
  .map(a => ({
  title: clean(a.title || ""),
  url: a.link || a.url || "",
  date: getDate(a),
  source: getSource(a),
  summary: getSummary(a),
  theme: getTheme(a)
}));

const sourceCountsAfter = {};
for (const a of filtered) {
  sourceCountsAfter[a.source] = (sourceCountsAfter[a.source] || 0) + 1;
}

const unknown_articles = filtered
  .filter(a => a.source === "Unknown")
  .map(a => ({
    title: a.title,
    url: a.url
  }));

return [
  {
    json: {
      article_count_after: filtered.length,
      unknown_articles,
      articles: filtered
    }
  }
];

const raw = $json.output?.[0]?.content?.[0]?.text || "";

const cleaned = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/, "")
  .trim();

const parsed = JSON.parse(cleaned);

return [
  {
    json: parsed
  }
];

const originalInput = $('Code in JavaScript').first().json || {};
const scoringInput = $('Code in JavaScript1').first().json || {};

const originalArticles = originalInput.articles || [];
const selectedArticles = scoringInput.selected_articles || [];

const selectedMap = new Map(
  selectedArticles.map(item => [item.title, item])
);

const merged = originalArticles
  .filter(article => selectedMap.has(article.title))
  .map(article => {
    const scored = selectedMap.get(article.title);
    return {
      ...article,
      theme: scored.theme || article.theme || "",
      editorial_score: scored.editorial_score || 0,
      why_keep: scored.why_keep || ""
    };
  })
  .sort((a, b) => (b.editorial_score || 0) - (a.editorial_score || 0));

return [
  {
    json: {
      selected_articles: merged,
      selected_count: merged.length
    }
  }
];

const articles = $json.selected_articles || [];

return articles.map(article => ({
  json: {
    Title: article.title,
    URL: article.url,
    "Date Sent": new Date().toISOString()
  }
}));

const currentInput = $('Code in JavaScript').first().json || {};
const notionItems = $input.all().map(item => item.json);

// titres déjà envoyés, normalisés
const sentTitles = new Set(
  notionItems
    .map(item => (item.property_title || item.name || "").toLowerCase().trim())
    .filter(Boolean)
);

const currentArticles = currentInput.articles || [];

const freshArticles = currentArticles.filter(article => {
  const title = (article.title || "").toLowerCase().trim();
  return !sentTitles.has(title);
});

return [
  {
    json: {
      article_count_before_memory: currentArticles.length,
      article_count_after_memory: freshArticles.length,
      articles: freshArticles
    }
  }
];
